!function(){const searchInput=document.getElementById("searchInput"),searchForm=document.getElementById("search-form");if(searchInput&&searchForm){let searchTimer;searchInput.addEventListener("input",(function(){clearTimeout(searchTimer),searchTimer=setTimeout((function(){searchForm.submit()}),400)})),searchForm.addEventListener("submit",(function(){searchForm.querySelectorAll('input[name="page"]').forEach((function(el){el.remove()}))}))}const modal=document.getElementById("rbiaConfirmModal"),modalName=document.getElementById("rbiaModalName"),modalLink=document.getElementById("rbiaModalConfirm"),btnCancel=document.getElementById("rbiaModalCancel");function closeModal(){modal.classList.remove("active")}document.querySelectorAll(".rbia-generate-btn").forEach((function(btn){btn.addEventListener("click",(function(){modalName.textContent=btn.dataset.name,modalLink.href=btn.dataset.href,modal.classList.add("active"),setTimeout((function(){modalLink.focus()}),50)}))})),btnCancel.addEventListener("click",closeModal),modal.addEventListener("click",(function(e){e.target===modal&&closeModal()})),document.addEventListener("keydown",(function(e){modal.classList.contains("active")&&"Escape"===e.key&&closeModal()})),modalLink.addEventListener("click",(function(){setTimeout(closeModal,100)}))}();